ShareReceiverActivity.kt
package com.example.sharesample

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity
import com.bumptech.glide.Glide

class ShareReceiverActivity : AppCompatActivity() {

    private lateinit var sharedContentTextView: TextView
    private lateinit var sharedImageView: ImageView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        sharedContentTextView = findViewById(R.id.sharedContentTextView)
        sharedImageView = findViewById(R.id.sharedImageView)

        handleIntent(intent)
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent) // Update the activity's intent
        handleIntent(intent)
    }

    private fun handleIntent(intent: Intent?) {
        intent?.let {
            when (it.action) {
                Intent.ACTION_SEND -> {
                    if (it.type?.startsWith("image/") == true) {
                        handleSendImage(it)
                    } else if (it.type == "text/plain") {
                        handleSendText(it)
                    }
                }
                Intent.ACTION_SEND_MULTIPLE -> {
                    if (it.type?.startsWith("image/") == true) {
                        handleSendMultipleImages(it)
                    }
                    // For multiple text, it's less common, usually handled as single text or a list of texts.
                    // For simplicity, we'll focus on multiple images for SEND_MULTIPLE.
                }
            }
        }
    }

    private fun handleSendText(intent: Intent) {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        sharedText?.let {
            sharedContentTextView.text = "Shared Text/URL:\n$it"
            sharedImageView.setImageDrawable(null) // Clear image if text is shared
            sharedImageView.visibility = ImageView.GONE
            sharedContentTextView.visibility = TextView.VISIBLE
        }
    }

    private fun handleSendImage(intent: Intent) {
        val imageUri: Uri? = intent.getParcelableExtra(Intent.EXTRA_STREAM)
        imageUri?.let {
            sharedContentTextView.text = "Shared Image:"
            sharedContentTextView.visibility = TextView.VISIBLE
            sharedImageView.visibility = ImageView.VISIBLE
            // Use Glide to load the image from Uri
            Glide.with(this)
                .load(it)
                .into(sharedImageView)
        }
    }

    private fun handleSendMultipleImages(intent: Intent) {
        val imageUris: ArrayList<Uri>? = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM)
        imageUris?.let {
            if (it.isNotEmpty()) {
                sharedContentTextView.text = "Shared Multiple Images (showing first one):"
                sharedContentTextView.visibility = TextView.VISIBLE
                sharedImageView.visibility = ImageView.VISIBLE
                // For simplicity, display only the first image.
                // In a real app, you'd likely use a RecyclerView or similar to show all.
                Glide.with(this)
                    .load(it[0])
                    .into(sharedImageView)
            }
        }
    }
}

